  it("includes native skills in the description even when skills are pre-seeded", async () => {
    //#given
    const tool = createSkillTool({
      skills: [createMockSkill("seeded-skill")],
      nativeSkills: {
        all() {
          return [{
            name: "native-visible-skill",
