          }]
        },
        async get() { return undefined },
        async dirs() { return [] },
      },
    })

    //#when
    const result = await tool.execute({ name: "external-plugin-skill" }, mockContext)

    //#then
    expect(result).toContain("external-plugin-skill")
    expect(result).toContain("External plugin skill body")
